      </div>
      <script>
      (() => {
        const root  = document.getElementById('hlstats-search');
        const input = document.getElementById('hlstatsSearchQ');
        const panel = document.getElementById('hlstatsSearchPanel');

        let last_q    = '';
        let last_st   = '';
        let last_game = '';

        if (!root || !input || !panel) return;
      
        const open = () => root.classList.add('is-open');
        const close = () => root.classList.remove('is-open');
      
        input.addEventListener('focus', open);
        input.addEventListener('click', open);
      
        document.addEventListener('click', (e) => {
          if (!root.contains(e.target)) close();
        });

        document.addEventListener('keydown', (e) => {
          if (e.key === 'Escape') close();
        });

        const submitElement = document.getElementById('hlstatsSearchSubmit');

        submitElement.addEventListener('click', function (e) {
            e.preventDefault();

            let q=input.value;
            let st=document.getElementsByName('st')[0].value;
            let game=document.getElementsByName('game')[0].value;

            if (!input.value.trim()) return false;
            if (q == last_q && st == last_st &&  game == last_game) return false;
            last_q    = q;
            last_st   = st;
            last_game = game;

            const params = new URLSearchParams({ mode: 'search', ajax: 'search', q, st, game });
            Fetch.run('<?=$baseUrl?>?' + params.toString(), 'hlstats-contents');
        });

      })();
      </script>
    </div>
  </div>
</div>

<div id="hlstats-contents" class="hlstats-contents <?=$mode?>">
