$bannerSrc = '';
if (!empty($g_options['bannerfile']) && $g_options['bannerdisplay'] != 0 && ($mode == 'contents' || $g_options['bannerdisplay']==1)) {
    if (preg_match('/^https?:\/\//i', $g_options['bannerfile']) && filter_var($g_options['bannerfile'], FILTER_VALIDATE_URL)) {
        $bannerSrc = $g_options['bannerfile'];
    } else {
        $bannerSrc = IMAGE_PATH . '/' . basename($g_options['bannerfile']);
    }

    if ($bannerSrc !== '') {
    ?>    
        <div class="hlstats-banner">
            <img src="<?php echo htmlspecialchars($bannerSrc, ENT_QUOTES, 'UTF-8'); ?>" alt="Banner" />
        </div>
     <?php
    }
}
